use fastly::request::Request;
use fastly::response::Response;
use fastly::service::Service;
use fastly::tls::TlsSettings;

// Define backend configurations
struct Backend {
    host: String,
    port: u16,
    sni: Option<String>,
    tls_settings: Option<TlsSettings>,
}

// Create a service with routing logic
let mut service = Service::new();

// Define backend connections
let backend1 = Backend {
    host: "backend1.example.com".to_string(),
    port: 443,
    sni: Some("backend1.example.com".to_string()),
    tls_settings: Some(TlsSettings::default()),
};

let backend2 = Backend {
    host: "backend2.example.com".to_string(),
    port: 80,
    sni: None,
    tls_settings: None,
};

// Route requests based on request path
service.route("/", |req| {
    if req.path().starts_with("/api/") {
        handle_request(&backend1, req)
    } else {
        handle_request(&backend2, req)
    }
});

// Function to handle requests to a specific backend
async fn handle_request(backend: &Backend, req: &Request) -> Response {
    // Create a client with the backend configuration
    let client = req.client().tls_settings(backend.tls_settings.clone());

    // Send the request to the backend
    let res = client.send(req.clone()).await;

    // Return the response
    res.unwrap_or_else(|_| Response::new(500))
}